    }

    if (promise._onSuccess)
      promise._onSuccess(data, i);
  },
  function (errorCode, errorMessage) {
    if (promise._onFail)
      promise._onFail(errorCode, errorMessage, i);
  });

  return promise;
};
""" % (jsName, pyName)

        return src

    def py_client(self, app_url):
        src = ""
        src += """
