def new_session(permissions):
    import random, string
    s = ''.join(random.choice(string.ascii_lowercase + string.digits) for _ in range(8))
    _sessions[s] = {}
    _sessions[s]["permissions"] = permissions[:]
    return s

def del_session(i):
    if i and "session" in i:
        if i["session"] != "":
            session = i["session"]
            del _sessions[session]

def get_session(i):
    session = None
    if i and "session" in i:
        s = i["session"]
        if s in _sessions:
            session = _sessions[s]
    return session

def get_active_sessions():
    return _sessions

def has_one_of(i, permissions):
    if len(permissions) == 0:
        raise Exception("At least one permission should be specified.")
    session = get_session(i)
    if not session:
        return False
    for needed in permissions:
        for actual in session["permissions"]:
            if needed == actual:
                return True

def needs_one_of(i, permissions):
    if not has_one_of(i, permissions):
        raise Exception("Unauthorized.")


import os
import argparse

import yaml
import cherrypy
from more_itertools.recipes import consume

from . import datastore
from .pastebin import BASE, Server


def get_args():
    parser = argparse.ArgumentParser()
    parser.add_argument(
        '-c', '--config', dest="configs",
        default=[], action="append", help="config file")
    parser.add_argument(
        '--yaml-config', dest="configs",
        type=load_yaml, action="append", help="yaml config")
    parser.add_argument(
        '--yaml-config-env', dest="configs",
        type=load_yaml_env, action="append", help="yaml config")
    return parser.parse_args()


def load_yaml(filename):
    """
    Given a param, load the YAML config from a file.
    """
    return yaml.load(open(filename))


def load_yaml_env(env_var_name):
    """
    Resolve the env var to a filename and load the YAML config from there.
    """
    return load_yaml(os.environ[env_var_name])


def main():
    args = get_args()

    # Cherrypy configuration here
    app_conf = {
        'global': {
            'server.socket_host': '::0',
        },
        '/static': {
            'tools.staticdir.on': True,
            'tools.staticdir.dir': os.path.join(BASE, 'static'),
        },
        'lexers': {'favorites': ['python']},
        'branding': {
            'name': 'Library',
            'logo source': '/static/librarypaste.png',
        }
    }

    app = cherrypy.tree.mount(root=None)
    app.merge(app_conf)
    consume(map(app.merge, args.configs))

    app.config.setdefault('datastore', dict(
        factory='librarypaste.jsonstore:JsonDataStore',
        repo=os.path.join(os.getcwd(), 'repo'),
    ))

    # after merging all the configs, initialize the datastore.
    app.config['datastore'].update(
        datastore=datastore.init_datastore(app.config['datastore']),
    )

    cherrypy.quickstart(Server(), '', config=app.config)


