"""Little X - Social graph backend over an object-spatial user graph."""

import datetime;

def _now() -> str {
    return datetime.datetime.utcnow().isoformat() + "Z";
}

# --- Graph archetypes: the persisted social graph ---
node Profile {
    has username: str = "";
    has bio: str = "";
    has created_at: str = "";
}

node Tweet {
    has content: str = "";
    has author_username: str = "";
    has created_at: str = "";
    has likes: list[str] = [];
    has comments: list[dict[str, str]] = [];
}

node Channel {
    has name: str = "";
    has description: str = "";
    has creator_username: str = "";
    has created_at: str = "";
}

edge Follow {}
edge Post {}
edge Member {}
edge ChannelPost {}

# --- View models: the typed contract returned to the client ---
obj UserView {
    has id: str;
    has username: str;
    has bio: str = "";
}

obj TweetView {
    has id: str;
    has content: str;
    has author_username: str;
    has created_at: str;
    has likes: list[str];
    has comments: list[dict[str, str]];
    has is_mine: bool = False;
}

obj ProfileView {
    has id: str;
    has username: str;
    has bio: str;
    has followers: list[UserView];
    has following: list[UserView];
    has tweets: list[TweetView];
}

obj ChannelView {
    has id: str;
    has name: str;
    has description: str;
    has creator_username: str;
    has created_at: str;
    has member_count: int;
    has is_member: bool;
    has posts: list[TweetView] = [];
}

obj TrendingTag {
    has tag: str;
    has count: int;
}

# --- View builders: turn graph nodes into view models ---
def _user_view(p: Profile) -> UserView {
    return UserView(id=jid(p), username=p.username, bio=p.bio);
}

def _tweet_view(t: Tweet, is_mine: bool) -> TweetView {
    return TweetView(
        id=jid(t),
        content=t.content,
        author_username=t.author_username,
        created_at=t.created_at,
        likes=t.likes,
        comments=t.comments,
        is_mine=is_mine
    );
}

# Sort keys -- typed so the type checker can resolve the comparison.
def _tweet_order(t: TweetView) -> str {
    return t.created_at;
}

def _channel_order(c: ChannelView) -> str {
    return c.created_at;
}

def _tag_order(t: TrendingTag) -> int {
    return t.count;
}

# Build the full ProfileView for a profile node -- shared by the
# `setup_profile` and `get_profile` walkers so both return the same type.
def _profile_view(me: Profile) -> ProfileView {
    my_id = jid(me);
    followers: list[UserView] = [];
    following: list[UserView] = [];
    for r in allroots() {
        for other in [r-->[?:Profile]] {
            if jid(other) != my_id {
                if [edge other->:Follow:->me] {
                    followers.append(_user_view(other));
                }
                if [edge me->:Follow:->other] {
                    following.append(_user_view(other));
                }
            }
        }
    }

    tweets: list[TweetView] = [_tweet_view(t, True) for t in [me-->[?:Tweet]]];
    tweets.sort(key=_tweet_order, reverse=True);

    return ProfileView(
        id=my_id,
        username=me.username,
        bio=me.bio,
        followers=followers,
        following=following,
        tweets=tweets
    );
}

# --- Walkers: object-spatial agents the client spawns ---
walker setup_profile {
    has username: str = "";
    has bio: str = "";
    has reports: list[ProfileView] = [];

    can run with Root entry {
        profiles = [-->[?:Profile]];
        if not profiles {
            new_profile = here ++> Profile(
                username=self.username, bio=self.bio, created_at=_now()
            );
            grant(new_profile[0], level=ConnectPerm);
            report _profile_view(new_profile[0]);
        } else {
            profile = profiles[0];
            if self.username {
                profile.username = self.username;
            }
            if self.bio {
                profile.bio = self.bio;

    has achievement_id: str;
    has title: str;
    has description: str;
    has rarity: str = "common";
    has unlocked_at: str = "";
}

