        for r in allroots() {
            for prof in [r-->[?:Profile]] {
                for tweet in [prof-->[?:Tweet]] {
                    if jid(tweet) == self.tweet_id {
                        report _toggle_like(tweet, username);
                        disengage;
                    }
                }
                for channel in [prof-->[?:Channel]] {
                    for tweet in [channel-->[?:Tweet]] {
                        if jid(tweet) == self.tweet_id {
