            </div>
            <div className="h-2.5 w-full overflow-hidden rounded-full bg-muted">
                <div
                    className={"h-full rounded-full transition-all duration-700 ease-out " + barClass}
                    style={{"width": str(pct) + "%"}}
                />
            </div>
            {if sub {
                <span className="text-xs text-muted-foreground">{sub}</span>
            }}
        </div>;
}
